body:
- OS: Ubuntu 22.04.5
- Kernel: Linux 5.15.0-168-generic
- Verilator: Verilator 5.044 2026-01-01 rev v5.044 (also in 5.045 devel)

Compile time error:
```
%Error: Internal Error: error.sv:208:53: ../V3LinkDot.cpp:1237: Can't find instance insertion point at 'SA' in: 'SA.PER[0].PEC[0].PE'
                                       : ... note: In instance 'top_axi_tb'
  208 |       pe #(.WX(WX),.WK(WK),.WY(WY),.LM(LM),.LA(LA)) PE (
      |                                                     ^~
                        ... See the manual at https://verilator.org/verilator_doc.html?v=5.044 for more assistance.
```

To reproduce:

command:
```
verilator --top top_axi_tb --timing --cc error.sv --Mdir work
```

I apologize that I could not simplify my design further. Any simpler, the error vanishes.

error.sv:
```systemverilog
`timescale 1ns/1ps

module n_delay #(parameter N=1, NO=N==0?1:N, W=8)(input logic c,e,rng,rnl,input logic [W-1:0] i,output logic [W-1:0] o,output logic [NO*W-1:0] d);
endmodule

module mac #(parameter WX=4,WK=8,WY=16,LM=1,LA=1, localparam WM=WX+WK)(input wire clk,rstn,en,m_valid,m_first,input wire [WX-1:0] x,input wire [WK-1:0] k,output wire [WY-1:0] y);
  logic signed [WM-1:0] mul_result,m;
  logic signed [WY-1:0] a_result;
  n_delay #(.N(LA-1),.W(WY)) ad(.c(clk),.e(en),.rng(rstn),.rnl(rstn),.i(a_result),.o(y),.d());
endmodule

module pe #(parameter WX=4,WK=8,WY=16,LM=1,LA=1)(input logic clk,rstn,input logic en_mac,en_shift,m_first,m_valid,r_copy,input logic [WK-1:0] ki,input logic [WX-1:0] xi,input logic [WY-1:0] ri,output logic [WK-1:0] ko,output logic [WX-1:0] xo,output logic [WY-1:0] ro);
  logic [WY-1:0] ao;
  always @(posedge clk) if(!rstn) begin end
  mac #(.WX(WX),.WK(WK),.WY(WY),.LM(LM),.LA(LA)) MAC (.clk(clk),.rstn(rstn),.en(en_mac),.m_valid(m_valid),.m_first(m_first),.x(xi),.k(ki),.y(ao));
  always_ff @(posedge clk) if(!rstn) ro<='0;
endmodule

module axis_sa(input logic clk);
  genvar r,c;
  logic rstn;
  logic en_mac,en_shift;
  logic [10:0] r_copy,m_first,valid;
  logic [3:0][7:0][3:0] xo;
  logic [3:0][7:0][7:0] ko;
  logic [3:0][7:0][15:0] ro;

  for(r=0;r<4;r++) begin:PER
    for(c=0;c<8;c++) begin:PEC
      wire [3:0] xi;
      wire [7:0] ki;
      wire [15:0] ri;
      pe #(.WX(4),.WK(8),.WY(16),.LM(1),.LA(1)) PE (.clk(clk),.rstn(rstn),.en_mac(en_mac),.en_shift(en_shift),.m_first(m_first[(r+c)]),.m_valid(valid[(r+c)]),.r_copy(r_copy[(r+c)]),.ki(ki),.xi(xi),.ri(ri),.ko(ko[r][c]),.xo(xo[r][c]),.ro(ro[r][c]));
    end
  end
endmodule

module top(input logic clk);
  axis_sa SA (.clk(clk));
endmodule

module top_axi_tb;
  logic clk /*verilator public*/ = 0;
  top TOP(.clk(clk));
endmodule

```

